using ByteForge.Toolkit.Logging;

// Initialize logging with default console logger
Log.Initialize();

// Basic log messages at different levels
Log.Debug("Application starting up");
Log.Info("User authentication successful");
Log.Warn("Database connection pool is running low");
Log.Error("Failed to process payment", new Exception("Payment gateway timeout"));
Log.Fatal("Critical system failure - shutting down");

// Log with context information
Log.Info("Order processed", new { OrderId = 12345, CustomerId = "CUST001", Amount = 299.99 });

// Structured logging with correlation
using (Log.BeginScope("ProcessOrder"))
{
    Log.Info("Starting order validation");

    try
    {
        ValidateOrder(12345);
        Log.Info("Order validation completed successfully");

        ProcessPayment(299.99m);
        Log.Info("Payment processed successfully");
    }
    catch (Exception ex)
    {
        Log.Error("Order processing failed", ex);
        throw;
    }
}

// Configure file logging
var fileLoggerOptions = new FileLoggerOptions
{
    FilePath = @"C:\Logs\MyApp.log",
    MaxFileSizeBytes = 10 * 1024 * 1024, // 10 MB
    MaxFileCount = 5,
    AutoFlush = true
};

Log.Initialize(new FileLogger(fileLoggerOptions));

// Configure log levels
Log.SetMinimumLevel(LogLevel.Information);

// Log application events
Log.Info("Application started");
Log.Info($"Logging configured - File: {fileLoggerOptions.FilePath}");

try
{
    // Simulate application work
    for (int i = 1; i <= 100; i++)
    {
        if (i % 10 == 0)
        {
            Log.Info($"Processed {i} items");
        }

        // Simulate occasional errors
        if (i == 50)
        {
            Log.Warn("Reached halfway point - performance check needed");
        }

        if (i == 75)
        {
            Log.Error("Simulated error occurred", new InvalidOperationException("Test error"));
        }
    }

    Log.Info("Processing completed successfully");
}
catch (Exception ex)
{
    Log.Fatal("Application crashed", ex);
}
finally
{
    Log.Info("Application shutting down");
}

using ByteForge.Toolkit.Logging;

// Configure file logger with rotation
var options = new FileLoggerOptions
{
    FilePath = @"C:\Logs\Application\app.log",
    MaxFileSizeBytes = 5 * 1024 * 1024, // 5 MB per file
    MaxFileCount = 10,                    // Keep 10 files
    AutoFlush = true,                     // Immediate write to disk
    IncludeTimestamp = true,
    IncludeLogLevel = true,
    IncludeThreadId = true,
    DateTimeFormat = "yyyy-MM-dd HH:mm:ss.fff"
};

// Create logger
var fileLogger = new FileLogger(options);

// Test log rotation
for (int i = 0; i < 10000; i++)
{
    fileLogger.Log(LogLevel.Information, 
        $"Log entry {i:D5} - This is a test message to demonstrate log rotation functionality");

    // Occasionally log at different levels
    if (i % 100 == 0)
    {
        fileLogger.Log(LogLevel.Warning, $"Checkpoint reached: {i} entries logged");
    }

    if (i % 1000 == 0)
    {
        fileLogger.Log(LogLevel.Error, $"Milestone: {i} entries", 
            new Exception($"Test exception at entry {i}"));
    }
}

// Check log files created
var logDirectory = Path.GetDirectoryName(options.FilePath);
var logFiles = Directory.GetFiles(logDirectory, "app*.log")
    .OrderBy(f => f)
    .ToArray();

Console.WriteLine($"Created {logFiles.Length} log files:");
foreach (var file in logFiles)
{
    var info = new FileInfo(file);
    Console.WriteLine($"  {Path.GetFileName(file)} - {info.Length:N0} bytes");
}

using ByteForge.Toolkit.Logging;

// Create console logger
var consoleLogger = new ConsoleLogger();

// Demonstrate different log levels with colors
Console.WriteLine("Demonstrating console logging with color coding:");
Console.WriteLine();

consoleLogger.Log(LogLevel.Debug, "Debug message - detailed diagnostic information");
consoleLogger.Log(LogLevel.Information, "Information message - general application flow");
