    Action = "UpdateProfile", 
    Timestamp = DateTime.Now,
    IPAddress = "192.168.1.100"
};

consoleLogger.Log(LogLevel.Information, "User action performed", contextData);

// Demonstrate structured logging output
using (var correlationContext = new CorrelationContext("REQ-12345"))
