using ByteForge.Toolkit.Logging;

// Create individual loggers
var consoleLogger = new ConsoleLogger();

var fileLogger = new FileLogger(new FileLoggerOptions
{
    FilePath = @"C:\Logs\application.log",
    MaxFileSizeBytes = 10 * 1024 * 1024,
    MaxFileCount = 5
});

var errorFileLogger = new FileLogger(new FileLoggerOptions
{
    FilePath = @"C:\Logs\errors.log",
    MaxFileSizeBytes = 5 * 1024 * 1024,
    MaxFileCount = 3
});

// Create composite logger
var compositeLogger = new CompositeLogger();

// Add loggers with different minimum levels
compositeLogger.AddLogger(consoleLogger, LogLevel.Information);  // Console shows Info and above
compositeLogger.AddLogger(fileLogger, LogLevel.Debug);           // File logs everything
compositeLogger.AddLogger(errorFileLogger, LogLevel.Error);      // Error file only errors/fatal

// Test logging at different levels
Console.WriteLine("Testing composite logger with multiple outputs:");

compositeLogger.Log(LogLevel.Debug, "Debug information for troubleshooting");
compositeLogger.Log(LogLevel.Information, "Application started successfully");
compositeLogger.Log(LogLevel.Warning, "Configuration file not found, using defaults");
compositeLogger.Log(LogLevel.Error, "Database connection failed", 
    new Exception("Connection timeout"));
compositeLogger.Log(LogLevel.Fatal, "Critical error - application shutting down");

Console.WriteLine("\nLog distribution:");
Console.WriteLine("- Console: Info, Warning, Error, Fatal");
Console.WriteLine("- application.log: Debug, Info, Warning, Error, Fatal");
Console.WriteLine("- errors.log: Error, Fatal");

// Demonstrate conditional logging
for (int i = 0; i < 1000; i++)
{
    if (i % 100 == 0)
    {
        compositeLogger.Log(LogLevel.Information, $"Processed {i} items");
    }

    if (i % 10 == 0)
    {
        compositeLogger.Log(LogLevel.Debug, $"Processing item {i}");
    }

    // Simulate errors
    if (i % 150 == 0)
    {
        compositeLogger.Log(LogLevel.Error, $"Error processing item {i}", 
            new Exception($"Simulated error for item {i}"));
    }
}

using ByteForge.Toolkit.Logging;

// Configure session-based file logging
var sessionOptions = new SessionFileLoggerOptions
{
    BaseDirectory = @"C:\Logs\Sessions",
    FileNameFormat = "session_{sessionId}_{timestamp:yyyyMMdd_HHmmss}.log",
    MaxFileSizeBytes = 1 * 1024 * 1024, // 1 MB per session file
    MaxSessionFiles = 100,               // Keep 100 most recent sessions
    AutoCleanupOldSessions = true
};

var sessionLogger = new SessionFileLogger(sessionOptions);

// Simulate multiple user sessions
var userSessions = new[]
{
    new { UserId = "user001", SessionId = Guid.NewGuid().ToString() },
    new { UserId = "user002", SessionId = Guid.NewGuid().ToString() },
    new { UserId = "user003", SessionId = Guid.NewGuid().ToString() }
};

foreach (var session in userSessions)
{
    Console.WriteLine($"Starting session for {session.UserId}");

    // Start session logging
    sessionLogger.StartSession(session.SessionId);

    // Log session activities
    sessionLogger.Log(LogLevel.Information, $"User {session.UserId} logged in");
    sessionLogger.Log(LogLevel.Debug, "Loading user preferences");
    sessionLogger.Log(LogLevel.Information, "User dashboard displayed");

    // Simulate user actions
    for (int i = 1; i <= 20; i++)
    {
        sessionLogger.Log(LogLevel.Debug, $"User action {i}: {GetRandomUserAction()}");

        if (i % 5 == 0)
        {
            sessionLogger.Log(LogLevel.Information, $"Completed {i} actions");
        }

        // Simulate occasional errors
        if (i == 15)
        {
            sessionLogger.Log(LogLevel.Warning, "Slow database response detected");
        }
    }

    sessionLogger.Log(LogLevel.Information, $"User {session.UserId} logged out");

    // End session logging
    sessionLogger.EndSession(session.SessionId);

    Console.WriteLine($"Session {session.SessionId} logged to file");
}

// Show session files created
var sessionFiles = Directory.GetFiles(sessionOptions.BaseDirectory, "session_*.log");
Console.WriteLine($"\nCreated {sessionFiles.Length} session files:");

foreach (var file in sessionFiles.OrderBy(f => f))
{
    var info = new FileInfo(file);
    Console.WriteLine($"  {Path.GetFileName(file)} - {info.Length:N0} bytes");
}

string GetRandomUserAction()
{
    var actions = new[]
    {
        "Viewed profile", "Updated settings", "Downloaded report", 
        "Searched products", "Added to cart", "Processed payment",
        "Sent message", "Uploaded file", "Generated invoice"
    };

    var random = new Random();
    return actions[random.Next(actions.Length)];
}

using ByteForge.Toolkit.Logging;

// Initialize logging
Log.Initialize(new CompositeLogger()
    .AddLogger(new ConsoleLogger(), LogLevel.Information)
    .AddLogger(new FileLogger(new FileLoggerOptions 
    { 
        FilePath = "correlation_demo.log",
        IncludeCorrelationId = true 
    }), LogLevel.Debug));

// Simulate web request processing
await ProcessWebRequest("GET", "/api/users/12345");
await ProcessWebRequest("POST", "/api/orders");
await ProcessWebRequest("PUT", "/api/users/12345/profile");

async Task ProcessWebRequest(string method, string path)
{
    var requestId = Guid.NewGuid().ToString("N")[..8];

    // Create correlation context for the request
    using (var context = new CorrelationContext($"REQ-{requestId}"))
    {
        Log.Info($"Incoming request: {method} {path}");

        try
        {
            // Simulate request processing steps
            await ValidateRequest(method, path);
            await AuthenticateUser();
            await ProcessBusinessLogic(path);
            await GenerateResponse();

            Log.Info($"Request completed successfully: {method} {path}");
        }
        catch (Exception ex)
        {
            Log.Error($"Request failed: {method} {path}", ex);
            throw;
        }
    }
}

async Task ValidateRequest(string method, string path)
{
    Log.Debug("Starting request validation");

    // Simulate validation steps
    await Task.Delay(10);
    Log.Debug("Request headers validated");

    await Task.Delay(5);
    Log.Debug("Request body validated");

    if (path.Contains("invalid"))
    {
        throw new ArgumentException("Invalid path detected");
    }

    Log.Info("Request validation completed");
}

async Task AuthenticateUser()
{
    Log.Debug("Starting user authentication");

    // Simulate authentication
    await Task.Delay(20);
    Log.Debug("Checking authentication token");

    await Task.Delay(15);
    Log.Info("User authenticated successfully");
}

async Task ProcessBusinessLogic(string path)
{
    Log.Debug("Starting business logic processing");

    if (path.Contains("users"))
    {
        await ProcessUserOperation(path);
    }
    else if (path.Contains("orders"))
    {
        await ProcessOrderOperation();
    }
    else
    {
        Log.Warn($"Unknown operation for path: {path}");
    }

    Log.Info("Business logic processing completed");
}

async Task ProcessUserOperation(string path)
{
    Log.Debug("Processing user operation");

    if (path.Contains("profile"))
    {
        Log.Info("Updating user profile");
        await Task.Delay(30);
        Log.Debug("Profile validation completed");
        await Task.Delay(20);
        Log.Debug("Profile saved to database");
    }
    else
    {
        Log.Info("Retrieving user information");
        await Task.Delay(15);
        Log.Debug("User data loaded from database");
    }
}

async Task ProcessOrderOperation()
{
    Log.Debug("Processing order operation");
    Log.Info("Creating new order");

    await Task.Delay(25);
    Log.Debug("Inventory check completed");

    await Task.Delay(35);
    Log.Debug("Payment processing initiated");

    // Simulate potential error
    var random = new Random();
    if (random.Next(10) < 2) // 20% chance of error
    {
        throw new InvalidOperationException("Payment processing failed");
    }

    await Task.Delay(20);
    Log.Info("Order created successfully");
}

async Task GenerateResponse()
{
    Log.Debug("Generating response");

    await Task.Delay(10);
    Log.Debug("Response serialized");

    Log.Info("Response generated");
}

using ByteForge.Toolkit.Logging;
using System;
using System.IO;
using System.Threading.Tasks;

// Enterprise logging configuration service
public class LoggingService
{
    private readonly CompositeLogger _compositeLogger;
    private readonly FileLogger _applicationLogger;
    private readonly FileLogger _errorLogger;
    private readonly FileLogger _auditLogger;
    private readonly SessionFileLogger _sessionLogger;
    private readonly ConsoleLogger _consoleLogger;

    public LoggingService(string logDirectory = @"C:\Logs\MyApp")
    {
        Directory.CreateDirectory(logDirectory);

        // Configure different loggers for different purposes
        _consoleLogger = new ConsoleLogger();

        _applicationLogger = new FileLogger(new FileLoggerOptions
        {
            FilePath = Path.Combine(logDirectory, "application.log"),
            MaxFileSizeBytes = 20 * 1024 * 1024, // 20 MB
            MaxFileCount = 10,
            AutoFlush = false, // Better performance
            IncludeTimestamp = true,
            IncludeThreadId = true,
            DateTimeFormat = "yyyy-MM-dd HH:mm:ss.fff"
        });

        _errorLogger = new FileLogger(new FileLoggerOptions
        {
            FilePath = Path.Combine(logDirectory, "errors.log"),
            MaxFileSizeBytes = 10 * 1024 * 1024, // 10 MB
            MaxFileCount = 20, // Keep more error logs
            AutoFlush = true,  // Immediate write for errors
            IncludeTimestamp = true,
            IncludeLogLevel = true,
            IncludeThreadId = true
        });

        _auditLogger = new FileLogger(new FileLoggerOptions
        {
            FilePath = Path.Combine(logDirectory, "audit.log"),
            MaxFileSizeBytes = 50 * 1024 * 1024, // 50 MB
            MaxFileCount = 50, // Keep extensive audit trail
            AutoFlush = true,
            IncludeTimestamp = true
        });

        _sessionLogger = new SessionFileLogger(new SessionFileLoggerOptions
        {
            BaseDirectory = Path.Combine(logDirectory, "Sessions"),
            FileNameFormat = "session_{sessionId}_{timestamp:yyyyMMdd_HHmmss}.log",
            MaxFileSizeBytes = 5 * 1024 * 1024,
            MaxSessionFiles = 200,
            AutoCleanupOldSessions = true
        });

        // Create composite logger with appropriate levels
        _compositeLogger = new CompositeLogger();
        _compositeLogger.AddLogger(_consoleLogger, LogLevel.Information);
        _compositeLogger.AddLogger(_applicationLogger, LogLevel.Debug);
        _compositeLogger.AddLogger(_errorLogger, LogLevel.Warning);

        // Initialize static Log facade
        Log.Initialize(_compositeLogger);

        Log.Info("Logging service initialized");
        Log.Info($"Log directory: {logDirectory}");
    }

    public void LogAuditEvent(string userId, string action, object details = null)
    {
        var auditEntry = new
        {
            Timestamp = DateTime.UtcNow,
            UserId = userId,
            Action = action,
            Details = details,
            IPAddress = GetClientIPAddress(),
            UserAgent = GetUserAgent()
        };

        _auditLogger.Log(LogLevel.Information, $"AUDIT: {action}", auditEntry);
        Log.Debug($"Audit logged: {userId} - {action}");
    }

    public void StartUserSession(string userId, string sessionId)
    {
        _sessionLogger.StartSession(sessionId);
        _sessionLogger.Log(LogLevel.Information, $"Session started for user: {userId}");

        LogAuditEvent(userId, "SessionStarted", new { SessionId = sessionId });
    }

    public void EndUserSession(string userId, string sessionId)
    {
        _sessionLogger.Log(LogLevel.Information, $"Session ended for user: {userId}");
        _sessionLogger.EndSession(sessionId);

        LogAuditEvent(userId, "SessionEnded", new { SessionId = sessionId });
    }

    public async Task LogBusinessOperation(string operationType, string userId, Func<Task> operation)
    {
        var operationId = Guid.NewGuid().ToString("N")[..8];

        using (var context = new CorrelationContext($"OP-{operationId}"))
        {
            Log.Info($"Starting operation: {operationType}");
            LogAuditEvent(userId, $"OperationStarted", new { OperationType = operationType, OperationId = operationId });

            var stopwatch = System.Diagnostics.Stopwatch.StartNew();

            try
            {
                await operation();

                stopwatch.Stop();
                Log.Info($"Operation completed: {operationType} in {stopwatch.ElapsedMilliseconds}ms");
                LogAuditEvent(userId, $"OperationCompleted", new { 
                    OperationType = operationType, 
                    OperationId = operationId,
                    DurationMs = stopwatch.ElapsedMilliseconds
                });
            }
            catch (Exception ex)
            {
                stopwatch.Stop();
                Log.Error($"Operation failed: {operationType} in {stopwatch.ElapsedMilliseconds}ms", ex);
                LogAuditEvent(userId, $"OperationFailed", new { 
                    OperationType = operationType, 
                    OperationId = operationId,
                    DurationMs = stopwatch.ElapsedMilliseconds,
                    Error = ex.Message
                });
                throw;
            }
        }
    }

    public void LogPerformanceMetrics(string operation, TimeSpan duration, Dictionary<string, object> metrics = null)
    {
        var performanceData = new
        {
            Operation = operation,
            DurationMs = duration.TotalMilliseconds,
            Timestamp = DateTime.UtcNow,
            Metrics = metrics ?? new Dictionary<string, object>()
        };

        if (duration.TotalSeconds > 5)
        {
            Log.Warn($"Slow operation detected: {operation} took {duration.TotalSeconds:F2}s", performanceData);
        }
        else if (duration.TotalSeconds > 1)
        {
            Log.Info($"Performance: {operation} took {duration.TotalMilliseconds:F0}ms", performanceData);
        }
        else
        {
            Log.Debug($"Performance: {operation} took {duration.TotalMilliseconds:F0}ms", performanceData);
        }
    }

    private string GetClientIPAddress()
    {
        // In a real application, get from HttpContext
        return "192.168.1.100";
    }

    private string GetUserAgent()
    {
        // In a real application, get from HttpContext
        return "MyApp/1.0.0";
    }

    public void Dispose()
    {
        Log.Info("Logging service shutting down");

        _applicationLogger?.Dispose();
        _errorLogger?.Dispose();
        _auditLogger?.Dispose();
        _sessionLogger?.Dispose();
        _consoleLogger?.Dispose();
    }
}

// Sample business service that uses logging
public class UserService
{
    private readonly LoggingService _loggingService;

    public UserService(LoggingService loggingService)
    {
        _loggingService = loggingService;
    }

    public async Task<User> GetUserAsync(int userId)
    {
        await _loggingService.LogBusinessOperation("GetUser", userId.ToString(), async () =>
        {
            Log.Debug($"Loading user from database: {userId}");

            // Simulate database operation
            await Task.Delay(100);

            Log.Debug($"User data retrieved: {userId}");
        });

        return new User { Id = userId, Name = $"User {userId}", Email = $"user{userId}@example.com" };
    }

    public async Task CreateUserAsync(User user)
    {
        await _loggingService.LogBusinessOperation("CreateUser", user.Email, async () =>
        {
            Log.Info($"Creating new user: {user.Email}");

            // Validate user data
            if (string.IsNullOrEmpty(user.Email))
            {
                throw new ArgumentException("Email is required");
            }

            Log.Debug("User validation completed");

            // Simulate database save
            await Task.Delay(200);

            Log.Info($"User created successfully: {user.Email}");
        });

        _loggingService.LogAuditEvent("system", "UserCreated", new 
        { 
            UserId = user.Id, 
            Email = user.Email, 
            Name = user.Name 
        });
    }

    public async Task UpdateUserProfileAsync(int userId, UserProfile profile)
    {
        var stopwatch = System.Diagnostics.Stopwatch.StartNew();

        try
        {
            await _loggingService.LogBusinessOperation("UpdateUserProfile", userId.ToString(), async () =>
            {
                Log.Info($"Updating profile for user: {userId}");

                // Validate profile data
                Log.Debug("Validating profile data");
                await Task.Delay(50);

                // Save to database
                Log.Debug("Saving profile to database");
                await Task.Delay(150);

                // Update cache
                Log.Debug("Updating user cache");
                await Task.Delay(30);

                Log.Info($"Profile updated successfully for user: {userId}");
            });

            _loggingService.LogAuditEvent(userId.ToString(), "ProfileUpdated", profile);
        }
        finally
        {
            stopwatch.Stop();
            _loggingService.LogPerformanceMetrics("UpdateUserProfile", stopwatch.Elapsed, 
                new Dictionary<string, object> 
                { 
                    { "UserId", userId }, 
                    { "ProfileSize", profile?.ToString()?.Length ?? 0 } 
                });
        }
    }
}

// Data models
public class User
{
    public int Id { get; set; }
    public string Name { get; set; }
    public string Email { get; set; }
}

public class UserProfile
{
    public string FirstName { get; set; }
    public string LastName { get; set; }
    public DateTime? DateOfBirth { get; set; }
    public string PhoneNumber { get; set; }
}

// Main application demonstrating enterprise logging
public class Application
{
    private LoggingService _loggingService;
    private UserService _userService;

    public async Task RunAsync()
    {
        // Initialize logging
        _loggingService = new LoggingService();
        _userService = new UserService(_loggingService);

        try
        {
            Log.Info("Application starting");

            // Simulate user sessions and operations
            await SimulateUserSessions();

            Log.Info("Application completed successfully");
        }
        catch (Exception ex)
        {
            Log.Fatal("Application crashed", ex);
            throw;
        }
        finally
        {
            _loggingService?.Dispose();
        }
    }

    private async Task SimulateUserSessions()
    {
        var users = new[]
        {
            new { Id = 1, Email = "john.doe@company.com", SessionId = Guid.NewGuid().ToString() },
            new { Id = 2, Email = "jane.smith@company.com", SessionId = Guid.NewGuid().ToString() },
            new { Id = 3, Email = "bob.johnson@company.com", SessionId = Guid.NewGuid().ToString() }
        };

        var tasks = users.Select(async user =>
        {
            // Start user session
            _loggingService.StartUserSession(user.Id.ToString(), user.SessionId);

            try
            {
                // Get user data
                var userData = await _userService.GetUserAsync(user.Id);

                // Update profile
                var profile = new UserProfile
                {
                    FirstName = userData.Name.Split(' ')[0],
                    LastName = userData.Name.Split(' ').LastOrDefault(),
                    PhoneNumber = $"555-{1000 + user.Id}"
                };

                await _userService.UpdateUserProfileAsync(user.Id, profile);

                // Simulate some user activity
                for (int i = 0; i < 5; i++)
                {
                    Log.Debug($"User {user.Id} performed action {i + 1}");
                    await Task.Delay(100);
                }
            }
            catch (Exception ex)
            {
                Log.Error($"Error in user session {user.Id}", ex);
            }
            finally
            {
                // End user session
                _loggingService.EndUserSession(user.Id.ToString(), user.SessionId);
            }
        });

        await Task.WhenAll(tasks);
    }
}

// Program entry point
public class Program
{
    static async Task Main(string[] args)
    {
        var app = new Application();

        try
        {
            await app.RunAsync();
            Console.WriteLine("Application completed successfully. Check log files for details.");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Application failed: {ex.Message}");
        }
    }
}
